const TRIP_CUTOFF = Date.parse('2026-07-01T00:00:00Z'); // trip Jul 7-11; older = inert test traffic
const idsData = $('Fetch Published IDs').first().json;

if (idsData && !idsData.content && idsData.message && idsData.message !== 'Not Found') {
  throw new Error('published-ids.json fetch error: ' + idsData.message + ' — aborting to prevent re-publication');
}

let publishedIds;
if (idsData && idsData.content) {
  try {
    const decoded = Buffer.from(idsData.content.replace(/\s/g,''), 'base64').toString('utf8');
    publishedIds = new Set(JSON.parse(decoded).ids || []);
  } catch(e) { publishedIds = new Set(); }
} else {
  publishedIds = new Set();
}

const raw = $('Fetch AgentMail').first().json;
const msgs = raw.messages || raw.data || [];

const INREACH      = ['no.reply.inreach@garmin.com', '@garmin.com'];
const NOISE        = ['pierre@agentmail.to', '@nytromarketing.com', '@berteloot.org'];
const GARMIN_NOISE = /^(?:please note|automated message|do not reply)/i;
const DISPATCH_TAG = /^DISPATCH:\s*/i;
const INREACH_SUBJ = /inReach message from/i;
const LATLON       = /Lat\s+(-?\d+\.\d+)[\s,]+Lon\s+(-?\d+\.\d+)/i;
const SIG  = /\n+(?:Sent from (?:my )?Garmin[^\n]*|[^\n]* sent this message from[^\n]*)$/im;
const BOIL = /\n*(?:View the location or send a reply|Do not reply directly to this message|This message was sent to you using the inReach|Please Note: Replies to this email are not answered).*/is;
const AUTORESP = [
  'please note: replies to this email are not answered',
  'you cannot send a direct reply',
  'this is an automated message',
  'inreach product support team'
];

function isDispatch(m) {
  const ts = Date.parse(m.timestamp || m.received_at || m.date || '');
  if (!Number.isNaN(ts) && ts < TRIP_CUTOFF) return false; // pre-trip test messages: never dispatches
  const s    = (m.from || '').toLowerCase();
  const subj = m.subject || '';
  const prev = (m.preview || '').toLowerCase();
  if (NOISE.some(p => s.includes(p))) return false;
  if (/^(Re|Fwd?):/.test(subj)) return false;
  if (GARMIN_NOISE.test(subj)) return false;
  if (AUTORESP.some(x => prev.includes(x))) return false;
  if (INREACH.some(p => s.includes(p))) return true;
  if (DISPATCH_TAG.test(subj)) return true;
  if (INREACH_SUBJ.test(subj)) return true;
  return false;
}

function parse(m) {
  const body = (m.text || m.preview || '').trim();
  if (!body) return null;
  const ll = LATLON.exec(body);
  let clean = body.replace(SIG, '').replace(BOIL, '').replace(DISPATCH_TAG, '').trim();
  if (!clean || AUTORESP.some(x => clean.toLowerCase().includes(x))) return null;
  const iso = m.timestamp || m.created_at || new Date().toISOString();
  const dt  = new Date(iso);
  const p   = n => String(n).padStart(2,'0');
  const id  = `${dt.getUTCFullYear()}${p(dt.getUTCMonth()+1)}${p(dt.getUTCDate())}T${p(dt.getUTCHours())}${p(dt.getUTCMinutes())}${p(dt.getUTCSeconds())}Z`;
  const entry = { id, received_at: dt.toISOString().replace('.000Z','Z'), body: clean, source: 'inreach', raw_message_id: m.message_id || '' };
  if (ll) { entry.lat = parseFloat(ll[1]); entry.lon = parseFloat(ll[2]); }
  return entry;
}

const dispatches = [];
const seenMids  = new Set();               // dedup by message_id
const seenBodies = new Map();              // dedup by normalized body text → index in dispatches

for (const m of msgs) {
  if (!isDispatch(m)) continue;
  const mid = m.message_id || '';
  if (mid && publishedIds.has(mid)) continue;
  if (mid && seenMids.has(mid)) continue;
  if (mid) seenMids.add(mid);

  const entry = parse(m);
  if (!entry) continue;

  // Body-text deduplication — if same text already queued, keep whichever has GPS
  const normBody = entry.body.toLowerCase().replace(/\s+/g, ' ').trim();
  if (seenBodies.has(normBody)) {
    const existingIdx = seenBodies.get(normBody);
    const existingEntry = dispatches[existingIdx].entry;
    // Upgrade to GPS version if this copy has coordinates and the existing one doesn't
    if (typeof entry.lat === 'number' && typeof existingEntry.lat !== 'number') {
      dispatches[existingIdx] = { entry, raw_mid: mid };
    }
    // Always seal the duplicate message_id too
    if (mid) dispatches[existingIdx].extra_mids = [...(dispatches[existingIdx].extra_mids || []), mid];
    continue;
  }
  seenBodies.set(normBody, dispatches.length);
  dispatches.push({ entry, raw_mid: mid });
}

return [{ json: { dispatches, count: dispatches.length, published_ids_sha: idsData ? idsData.sha : null } }];

const jData = $('Fetch journal.html').first().json;
const rData = $('Fetch rss.xml').first().json;

// Guard: catch missing files early with a clear error
if (!jData || !jData.content) throw new Error('journal.html not found in GitHub repo — run initial setup');
if (!rData || !rData.content) throw new Error('rss.xml not found in GitHub repo — run initial setup');

const dispatches = $('Apply GPS + Reassemble').first().json.dispatches;

// Strip all whitespace (not just \n) from base64 before decoding — robust against RFC 2045 wrapping
const journalHtml = Buffer.from(jData.content.replace(/\s/g,''), 'base64').toString('utf8');
const rssXml      = Buffer.from(rData.content.replace(/\s/g,''), 'base64').toString('utf8');

function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function fmtDate(iso) {
  const dt = new Date(iso);
  const M  = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const p  = n => String(n).padStart(2,'0');
  return `${M[dt.getUTCMonth()]} ${p(dt.getUTCDate())}, ${dt.getUTCFullYear()} · ${p(dt.getUTCHours())}:${p(dt.getUTCMinutes())} UTC`;
}

// ── 1. Parse all existing <li> entries ────────────────────────────────────────
const S  = '<!-- LIVE_DISPATCHES:START -->';
const E  = '<!-- LIVE_DISPATCHES:END -->';
const si = journalHtml.indexOf(S);
const ei = journalHtml.indexOf(E);
if (si === -1 || ei === -1) throw new Error('LIVE_DISPATCHES markers not found in journal.html');

const existingBlock = journalHtml.slice(si + S.length, ei);
const LI_RE = /<li class="dispatch">[\s\S]*?<\/li>/g;
const existingLis = [];
let m;
while ((m = LI_RE.exec(existingBlock)) !== null) {
  const dtMatch = m[0].match(/datetime="([^"]+)"/);
  const bodyMatch = m[0].match(/<p class="dispatch__body">([^<]*)<\/p>/);
  existingLis.push({ dt: dtMatch ? dtMatch[1] : '', body: bodyMatch ? bodyMatch[1] : '', html: m[0] });
}

// ── 2. Build <li> HTML for new dispatches ────────────────────────────────────
const newLis = dispatches.map(({ entry }) => {
  let loc = '';
  if (typeof entry.lat === 'number') {
    const href = `https://www.google.com/maps/?q=${entry.lat},${entry.lon}`;
    loc = `        <a class="dispatch__loc" href="${href}" target="_blank" rel="noopener">📍 ${entry.lat.toFixed(4)}, ${entry.lon.toFixed(4)}</a>\n`;
  }
  return {
    dt: entry.received_at,
    body: entry.body,
    html: `<li class="dispatch">\n        <time class="dispatch__date" datetime="${esc(entry.received_at)}">${fmtDate(entry.received_at)}</time>\n        <p class="dispatch__body">${esc(entry.body)}</p>\n${loc}      </li>`
  };
});

// ── 3. Merge, deduplicate by datetime AND body text, sort newest-first ──────────
const seen = new Set();
const seenBodies = new Set();
const allLis = [];
for (const item of [...newLis, ...existingLis]) {
  if (item.dt && seen.has(item.dt)) continue;
  const normBody = (item.body || '').toLowerCase().replace(/\s+/g, ' ').trim();
  if (normBody && seenBodies.has(normBody)) continue;
  if (item.dt) seen.add(item.dt);
  if (normBody) seenBodies.add(normBody);
  allLis.push(item);
}
allLis.sort((a, b) => {
  const da = new Date(a.dt), db = new Date(b.dt);
  if (isNaN(da)) return 1;
  if (isNaN(db)) return -1;
  return db - da;
});

// ── 4. Rebuild journal.html ───────────────────────────────────────────────────
const olContent  = allLis.map(x => '      ' + x.html).join('\n');
const newBlock   = `\n      <ol class="dispatches">\n${olContent}\n      </ol>\n    `;
const newJournal = journalHtml.slice(0, si + S.length) + newBlock + journalHtml.slice(ei);

// ── 5. Prepend new items to rss.xml (newest first) ───────────────────────────
const SITE = 'https://canoe-verendrye.berteloot.org';
const DAYS = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
const MONS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
let newItems = '';
for (const { entry } of dispatches) {
  const dt  = new Date(entry.received_at);
  const p   = n => String(n).padStart(2,'0');
  const pub = `${DAYS[dt.getUTCDay()]}, ${p(dt.getUTCDate())} ${MONS[dt.getUTCMonth()]} ${dt.getUTCFullYear()} ${p(dt.getUTCHours())}:${p(dt.getUTCMinutes())}:${p(dt.getUTCSeconds())} +0000`;
  const loc = typeof entry.lat === 'number' ? ` · 📍 ${entry.lat.toFixed(4)}, ${entry.lon.toFixed(4)}` : '';
  const title = esc(entry.body.slice(0, 160)) + esc(loc);
  newItems += `  <item>\n    <title>${title}</title>\n    <link>${SITE}/journal.html</link>\n    <guid isPermaLink="false">${SITE}/dispatches/${entry.id}</guid>\n    <pubDate>${pub}</pubDate>\n    <description>${esc(entry.body)}${esc(loc)}</description>\n  </item>\n`;
}
const CC = '</channel>';
const ci = rssXml.lastIndexOf(CC);
// Insert new items BEFORE existing ones so RSS readers see newest first
const firstItem = rssXml.indexOf('<item>');
const ins = firstItem === -1 ? ci : firstItem;
const newRss = ci === -1 ? rssXml : rssXml.slice(0, ins) + newItems + rssXml.slice(ins);

return [{
  json: {
    journal_b64:   Buffer.from(newJournal).toString('base64'),
    rss_b64:       Buffer.from(newRss).toString('base64'),
    count:         dispatches.length,
    total_entries: allLis.length,
    preview:       dispatches.map(d => d.entry.body.slice(0, 80)).join(' | ')
  }
}];

const rj   = $('Render Journal').first().json;
const fp   = $('Apply GPS + Reassemble').first().json;
const pids = $('Fetch Published IDs').first().json;

// Decode base64 → UTF-8 (Buffer is available in Code nodes)
const journalHtml = Buffer.from(rj.journal_b64, 'base64').toString('utf8');
const rssXml      = Buffer.from(rj.rss_b64, 'base64').toString('utf8');

// Update published IDs
let existing = [];
if (pids && pids.content) {
  try { existing = JSON.parse(Buffer.from(pids.content.replace(/\s/g,''), 'base64').toString()).ids || []; } catch(e) {}
}
const newIds = fp.dispatches.flatMap(d => [d.raw_mid, ...(d.extra_mids || [])]).filter(Boolean);
const merged = Array.from(new Set([...existing, ...newIds])).slice(-500);
const idsContent = JSON.stringify({ ids: merged, updated_at: new Date().toISOString() }, null, 2) + '\n';

// Build tree array with decoded UTF-8 content
const tree = [
  { path: 'journal.html',                        mode: '100644', type: 'blob', content: journalHtml },
  { path: 'rss.xml',                              mode: '100644', type: 'blob', content: rssXml },
  { path: 'journal-entries/published-ids.json',  mode: '100644', type: 'blob', content: idsContent },
  ...fp.dispatches.map(d => ({
    path: `journal-entries/${d.entry.id}.json`,
    mode: '100644', type: 'blob',
    content: JSON.stringify(d.entry, null, 2) + '\n'
  }))
];

const count = fp.dispatches.length;
const preview = fp.dispatches.map(d => d.entry.body.slice(0, 60)).join(' | ');
return [{ json: { tree, count, preview, commit_message: `Pierre: ${count} new dispatch(es) from the trail` } }];

// Split dispatches into one item per dispatch so we can fetch each full body
const fp = $('Filter + Parse Dispatches').first().json;
return fp.dispatches.map(d => ({
  json: {
    encoded_mid: encodeURIComponent(d.raw_mid),
    raw_mid: d.raw_mid,
    entry: d.entry,
  }
}));

const LATLON = /Lat\s+(-?\d+\.\d+)[\s,]+Lon\s+(-?\d+\.\d+)/i;
const BOIL = /\n*(?:View the location or send a reply|Do not reply directly to this message|This message was sent to you using the inReach|Please Note: Replies to this email are not answered).*/is;
const SIG  = /\n+(?:Sent from (?:my )?Garmin[^\n]*|[^\n]* sent this message from[^\n]*)$/im;

const fullBodies = $input.all();
const splitItems = $('Split For Fetch').all();
const fpData     = $('Filter + Parse Dispatches').first().json;

const dispatches = fullBodies.map((item, i) => {
  const orig  = splitItems[i]?.json || {};
  const full  = item.json.text || item.json.extracted_text || '';
  const entry = { ...orig.entry };

  // Extract GPS from full body BEFORE stripping boilerplate
  const ll = LATLON.exec(full);
  if (ll) {
    entry.lat = parseFloat(ll[1]);
    entry.lon = parseFloat(ll[2]);
  } else {
    delete entry.lat;
    delete entry.lon;
  }

  // Use full body text for a cleaner message (strips Garmin boilerplate)
  if (full) {
    const clean = full.replace(SIG, '').replace(BOIL, '').trim();
    if (clean) entry.body = clean;
  }

  return { raw_mid: orig.raw_mid, entry };
});

return [{ json: { dispatches, count: dispatches.length, published_ids_sha: fpData.published_ids_sha } }];
